{"query":"select
  count(distinct a.dim_membership_key) filter (
    where exists (
      select 1 from dim.membership m
      where substring(m.membership_membership_number from '[0-9]+')::int = a.dim_membership_key
    )
  ) as matched_account_membership_keys,
  count(distinct m.dim_membership_key) filter (
    where exists (
      select 1 from dim.account a
      where substring(m.membership_membership_number from '[0-9]+')::int = a.dim_membership_key
    )
  ) as matched_memberships
from dim.account a
cross join lateral (select 1) x
left join dim.membership m on false;"}
